"""Bubble sort with extracted swap helper — behavior unchanged."""


def swap(xs, i, j):
    xs[i], xs[j] = xs[j], xs[i]


def sort_list(items):
    xs = list(items)
    n = len(xs)
    for i in range(n):
        for j in range(0, n - i - 1):
            if xs[j] > xs[j + 1]:
                swap(xs, j, j + 1)
    return xs
